'use strict';

var $RangeError = require('es-errors/range');
var $TypeError = require('es-errors/type');

var isInteger = require('math-intrinsics/isInteger');
var isTypedArray = require('is-typed-array');
var typedArrayBuffer = require('typed-array-buffer');
var typedArrayByteOffset = require('typed-array-byte-offset');
var typedArrayLength = require('typed-array-length');
var whichTypedArray = require('which-typed-array');

var Get = require('./Get');
var IsBigIntElementType = require('./IsBigIntElementType');
var IsDetachedBuffer = require('./IsDetachedBuffer');
var LengthOfArrayLike = require('./LengthOfArrayLike');
var SetValueInBuffer = require('./SetValueInBuffer');
var ToBigInt = require('./ToBigInt');
var ToNumber = require('./ToNumber');
var ToObject = require('./ToObject');
var ToString = require('./ToString');
var TypedArrayElementSize = require('./TypedArrayElementSize');
var TypedArrayElementType = require('./TypedArrayElementType');



module.exports = function SetTypedArrayFromArrayLike(target, targetOffset, source) {
	var whichTarget = whichTypedArray(target);
	if (!whichTarget) {
		throw new $TypeError('Assertion failed: target must be a TypedArray instance');
	}

	if (targetOffset !== Infinity && (!isInteger(targetOffset) || targetOffset < 0)) {
		throw new $TypeError('Assertion failed: targetOffset must be a non-negative integer or +Infinity');
	}

	if (isTypedArray(source)) {
		throw new $TypeError('Assertion failed: source must not be a TypedArray instance');
	}

	var targetBuffer = typedArrayBuffer(target); 

	if (IsDetachedBuffer(targetBuffer)) {
		throw new $TypeError('target’s buffer is detached'); 
	}

	var targetLength = typedArrayLength(target); 

	var targetElementSize = TypedArrayElementSize(target); 

	var targetType = TypedArrayElementType(target); 

	var targetByteOffset = typedArrayByteOffset(target); 

	var src = ToObject(source); 

	var srcLength = LengthOfArrayLike(src); 

	if (targetOffset === Infinity) {
		throw new $RangeError('targetOffset must be a finite integer'); 
	}

	if (srcLength + targetOffset > targetLength) {
		throw new $RangeError('targetOffset + srcLength must be <= target.length'); 
	}

	var targetByteIndex = (targetOffset * targetElementSize) + targetByteOffset; 

	var k = 0; 

	var limit = targetByteIndex + (targetElementSize * srcLength); 

	while (targetByteIndex < limit) { 
		var Pk = ToString(k); 

		var value = Get(src, Pk); 

		if (IsBigIntElementType(targetType)) {
			value = ToBigInt(value); 
		} else {
			value = ToNumber(value); 
		}

		if (IsDetachedBuffer(targetBuffer)) {
			throw new $TypeError('target’s buffer is detached'); 
		}

		SetValueInBuffer(targetBuffer, targetByteIndex, targetType, value, true, 'Unordered'); 

		k += 1; 

		targetByteIndex += targetElementSize; 
	}
};
